const body = $input.first().json.body || $input.first().json || {};
const firstFrame = body.firstFrame;
const lastFrame = body.lastFrame;

if (!firstFrame || !firstFrame.base64 || !firstFrame.mimeType) {
  throw new Error('Payload tidak memiliki firstFrame.base64 / firstFrame.mimeType');
}

const hasLastFrame = Boolean(lastFrame && lastFrame.base64 && lastFrame.mimeType);
const userCaption = String(body.userCaption || '').trim();
const aspectRatio = String(body.aspectRatio || '9:16').trim();

const systemIntent = userCaption
  ? 'User mengirim caption. Pertahankan maksud user; pahami gambar (1 atau 2) sebagai referensi visual; susun prompt video Veo sinematik English.'
  : 'User tidak mengirim caption. Pahami gambar secara visual; buat ide video otomatis dari objek, suasana, dan konteks.';
const frameMode = hasLastFrame
  ? 'Ada dua gambar referensi: frame pertama (mulai) dan frame terakhir (akhir). Susun prompt video sebagai transisi halus dari gambar pertama ke gambar kedua. Sebutkan kontinuitas subjek, kamera, dan lighting.'
  : 'Ada satu gambar referensi sebagai frame pertama. Susun prompt video image-to-video dengan kamera & aksi natural.';

const geminiInstruction = `Kamu adalah AI agent kreatif berbahasa Indonesia yang menyiapkan prompt video untuk Google Veo 3.
${systemIntent}
${frameMode}

Output harus JSON valid saja, tanpa markdown:
{
  \"image_summary_id\": \"ringkasan gambar dalam Bahasa Indonesia\",
  \"user_intent_id\": \"maksud user atau auto-generated bila caption kosong\",
  \"veo_prompt_en\": \"prompt final Bahasa Inggris untuk Veo, deskriptif, cinematic, camera movement, subject action, environment, lighting, mood, audio cues\",
  \"negative_prompt_en\": \"hal yang perlu dihindari\",
  \"telegram_caption_id\": \"caption singkat Bahasa Indonesia\"
}

Aturan:
- veo_prompt_en wajib English. Semua value JSON wajib satu baris (tanpa line break mentah).
- Jangan pakai tanda kutip ganda tidak ter-escape di dalam string.
- Cocok untuk image-to-video: gerakan kamera natural, aksi halus, tidak merusak objek utama.
- Hindari klaim palsu, konten berbahaya, wajah orang nyata bila tidak jelas izinnya.

Caption user:
${userCaption || '(caption kosong, buat ide otomatis dari gambar)'}`;

return [{
  json: {
    source: body.source || 'porto-web',
    requestId: body.requestId || `${Date.now()}`,
    userEmail: body.userEmail || null,
    userCaption,
    hasUserCaption: userCaption.length > 0,
    aspectRatio,
    hasLastFrame,
    firstFrameBase64: firstFrame.base64,
    firstFrameMime: firstFrame.mimeType,
    lastFrameBase64: hasLastFrame ? lastFrame.base64 : '',
    lastFrameMime: hasLastFrame ? lastFrame.mimeType : '',
    projectId: $env.GCP_PROJECT_ID || 'project-8fa51551-4f6c-4ff6-8b7',
    geminiLocation: 'global',
    veoLocation: $env.VEO_LOCATION || 'us-central1',
    geminiModel: $env.GEMINI_MODEL || 'gemini-2.5-pro',
    // Veo 3.0 GA (veo-3.0-generate-001) MENOLAK image-to-video dengan error
    // 'The request is not supported by this model'. Image-to-video + lastFrame
    // hanya jalan di Veo 3.1. Default fast variant biar lebih cepat (~1-2 menit).
    veoModel: $env.VEO_MODEL || 'veo-3.1-fast-generate-001',
    veoDurationSeconds: Number($env.VEO_DURATION_SECONDS) || 8,
    veoResolution: $env.VEO_RESOLUTION || '720p',
    veoGenerateAudio: String($env.VEO_GENERATE_AUDIO || 'true').toLowerCase() !== 'false',
    geminiInstruction,
  },
}];

const item = $input.first().json;
const parts = [{ text: item.geminiInstruction }, { inlineData: { mimeType: item.firstFrameMime, data: item.firstFrameBase64 } }];
if (item.hasLastFrame) {
  parts.push({ inlineData: { mimeType: item.lastFrameMime, data: item.lastFrameBase64 } });
}
return [{
  json: {
    ...item,
    geminiBody: {
      contents: [{ role: 'user', parts }],
      generationConfig: { temperature: 0.75, maxOutputTokens: 2500, responseMimeType: 'application/json' },
    },
  },
}];

const meta = $('Build Gemini Body').first().json;
const response = $input.first().json;

function stripCodeFence(value) {
  return String(value || '').replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
}
function objectLikeText(value) {
  const cleaned = stripCodeFence(value);
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  return firstBrace >= 0 && lastBrace > firstBrace ? cleaned.slice(firstBrace, lastBrace + 1) : cleaned;
}

if (response.error) throw new Error(response.error.message || JSON.stringify(response.error));
const parts = response.candidates?.[0]?.content?.parts || [];
const text = parts.map((part) => part.text || '').join('\n').trim();
if (!text) throw new Error('Gemini response kosong');

let parsed;
try { parsed = JSON.parse(objectLikeText(text)); }
catch (e) { parsed = { veo_prompt_en: stripCodeFence(text), negative_prompt_en: '', telegram_caption_id: 'Video selesai dibuat.' }; }

const veoPrompt = String(parsed.veo_prompt_en || '').trim();
if (!veoPrompt) throw new Error('Output Gemini tidak memiliki veo_prompt_en');

return [{
  json: {
    ...meta,
    veoPrompt,
    negativePrompt: String(parsed.negative_prompt_en || 'blurry, distorted, low quality, broken text, extra limbs').trim(),
    imageSummary: parsed.image_summary_id || '',
  },
}];

const item = $input.first().json;
function sanitize(value) {
  let prompt = String(value || '').trim();
  const replacements = [
    [/\b(blood|bloody|gore|gory|corpse|dead body|decapitat\w*|dismember\w*)\b/gi, 'red visual detail'],
    [/\b(kill|killing|murder|suicide|self[- ]?harm|harmful injury|stab\w*|shoot\w*)\b/gi, 'dramatic tension'],
    [/\b(gun|rifle|pistol|knife|blade|weapon|bomb|explosive|explosion)\b/gi, 'neutral prop'],
    [/\b(nude|naked|sex|sexual|erotic|fetish|porn\w*)\b/gi, 'tasteful lifestyle'],
    [/\b(child|children|kid|minor|underage)\b/gi, 'person'],
    [/\b(drug|cocaine|heroin|meth|marijuana|weed|narcotic)\b/gi, 'wellness product'],
    [/\b(hate|racist|slur|terrorist|extremist)\b/gi, 'neutral social context'],
  ];
  for (const [pattern, replacement] of replacements) prompt = prompt.replace(pattern, replacement);
  prompt = prompt.replace(/\s+/g, ' ').replace(/[""]/g, '"').replace(/['']/g, "'").trim();
  const safetyPrefix = 'Safe, policy-compliant cinematic video. No violence, no gore, no explicit sexual content, no minors, no weapons, no illegal activity, no hate symbols.';
  return (safetyPrefix + ' ' + prompt).slice(0, 3000);
}

const safePrompt = sanitize(item.veoPrompt);
const safeNegative = [
  item.negativePrompt || '',
  'violence, gore, blood, weapons, explicit sexual content, nudity, minors, illegal drugs, hate symbols, self harm, realistic injury, disturbing content',
].filter(Boolean).join(', ');

return [{ json: { ...item, veoPromptOriginal: item.veoPrompt, veoPrompt: safePrompt, negativePrompt: safeNegative } }];

const item = $input.first().json;
const instance = {
  prompt: item.veoPrompt,
  image: { bytesBase64Encoded: item.firstFrameBase64, mimeType: item.firstFrameMime },
};
if (item.hasLastFrame) {
  instance.lastFrame = { bytesBase64Encoded: item.lastFrameBase64, mimeType: item.lastFrameMime };
}
const veoBody = {
  instances: [instance],
  parameters: {
    sampleCount: 1,
    durationSeconds: item.veoDurationSeconds,
    aspectRatio: item.aspectRatio,
    generateAudio: item.veoGenerateAudio,
    resolution: item.veoResolution,
    negativePrompt: item.negativePrompt,
    personGeneration: 'allow_adult',
  },
};
return [{ json: { ...item, veoBody } }];

const meta = $('Build Veo Body').first().json;
const raw = $input.first().json;
// neverError + fullResponse → raw bentuknya { statusCode, headers, body }.
const statusCode = Number(raw.statusCode || raw.status || 0);
const body = raw.body ?? raw;

if (!statusCode || statusCode >= 400) {
  const errObj = body?.error || body;
  const message = errObj?.message || (typeof body === 'string' ? body : JSON.stringify(body)).slice(0, 1500);
  const veoModel = meta.veoModel;
  const hint = String(message).toLowerCase().includes('not supported by this model')
    ? ` Hint: model '${veoModel}' kemungkinan tidak mendukung image-to-video. Gunakan veo-3.1-fast-generate-001 atau veo-3.1-generate-001 (set env VEO_MODEL).`
    : '';
  throw new Error(`Veo predictLongRunning gagal (HTTP ${statusCode || 'unknown'}): ${message}.${hint}`);
}

const operationName = body?.name || body?.operationName || body?.operation?.name;
if (!operationName) {
  throw new Error('operationName tidak ditemukan di response Veo: ' + JSON.stringify(body).slice(0, 1500));
}
return [{ json: { ok: true, operationName, requestId: meta.requestId, source: meta.source, veoModel: meta.veoModel } }];

const body = $input.first().json.body || $input.first().json || {};
if (!body.operationName) throw new Error('operationName wajib');
return [{
  json: {
    requestId: body.requestId || '',
    operationName: body.operationName,
    projectId: $env.GCP_PROJECT_ID || 'project-8fa51551-4f6c-4ff6-8b7',
    veoLocation: $env.VEO_LOCATION || 'us-central1',
    // Harus match dengan model yang dipakai di Parse Payload Start.
    veoModel: $env.VEO_MODEL || 'veo-3.1-fast-generate-001',
  },
}];

const meta = $('Parse Payload Status').first().json;
const response = $input.first().json;
if (response.error) {
  return [{ json: { ok: false, done: true, error: response.error.message || JSON.stringify(response.error), requestId: meta.requestId } }];
}
const done = Boolean(response.done);
const operationError = response.error || response.response?.error;
if (operationError) {
  return [{ json: { ok: false, done: true, error: operationError.message || JSON.stringify(operationError), requestId: meta.requestId } }];
}
if (!done) {
  return [{ json: { ok: true, done: false, requestId: meta.requestId } }];
}
const payload = response.response || response;
const videos = payload.videos || payload.generatedVideos || payload.predictions?.[0]?.videos || [];
const first = Array.isArray(videos) ? videos[0] : videos;
const video = first?.video || first || {};
const videoBase64 = video.bytesBase64Encoded || video.data || first?.bytesBase64Encoded;
const gcsUri = video.gcsUri || first?.gcsUri;
if (!videoBase64) {
  return [{ json: { ok: false, done: true, error: gcsUri ? `Veo mengembalikan gcsUri (${gcsUri}) bukan base64. Hapus storageUri di body Veo.` : 'Veo done tetapi tanpa videoBase64', requestId: meta.requestId } }];
}
return [{ json: { ok: true, done: true, videoBase64, mimeType: video.mimeType || first?.mimeType || 'video/mp4', requestId: meta.requestId } }];
